defmodule AdminDashboardWeb.UserController do
  use AdminDashboardWeb, :controller
  alias AdminDashboard.UserQuery

  def index(conn, params) do
    role = params["role"]
    
    users = case role do
      nil -> {:ok, []}
      role -> UserQuery.get_users_by_role(role)
    end

    case users do
      {:ok, user_list} -> 
        json(conn, %{users: user_list})
      {:error, _} -> 
        conn
        |> put_status(:internal_server_error)
        |> json(%{error: "Failed to fetch users"})
    end
  end

  def search(conn, %{"q" => search_term}) do
    case UserQuery.search_users(search_term) do
      {:ok, users} -> json(conn, %{users: users})
      {:error, _} -> 
        conn
        |> put_status(:internal_server_error)
        |> json(%{error: "Search failed"})
    end
  end

  def filter(conn, params) do
    filters = Map.to_list(params)
    
    case UserQuery.filter_users(filters) do
      {:ok, users} -> json(conn, %{users: users})
      {:error, _} -> 
        conn
        |> put_status(:internal_server_error)
        |> json(%{error: "Filter failed"})
    end
  end

  def show(conn, %{"id" => id}) do
    case UserQuery.get_user_by_id(id) do
      {:ok, user} -> json(conn, %{user: user})
      {:error, _} -> 
        conn
        |> put_status(:not_found)
        |> json(%{error: "User not found"})
    end
  end

  def delete(conn, %{"id" => id}) do
    case UserQuery.delete_user(id) do
      {:ok, _} -> json(conn, %{message: "User deleted"})
      {:error, _} -> 
        conn
        |> put_status(:internal_server_error)
        |> json(%{error: "Delete failed"})
    end
  end

  def update_role(conn, %{"id" => id, "role" => role}) do
    case UserQuery.update_user_role(id, role) do
      {:ok, _} -> json(conn, %{message: "Role updated"})
      {:error, _} -> 
        conn
        |> put_status(:internal_server_error)
        |> json(%{error: "Update failed"})
    end
  end

  def date_range(conn, %{"start" => start_date, "end" => end_date}) do
    case UserQuery.get_users_by_date_range(start_date, end_date) do
      {:ok, users} -> json(conn, %{users: users})
      {:error, _} -> 
        conn
        |> put_status(:internal_server_error)
        |> json(%{error: "Query failed"})
    end
  end

  def custom_filter(conn, %{"column" => column, "operator" => operator, "value" => value}) do
    case UserQuery.get_users_with_custom_filter(column, operator, value) do
      {:ok, users} -> json(conn, %{users: users})
      {:error, _} -> 
        conn
        |> put_status(:internal_server_error)
        |> json(%{error: "Query failed"})
    end
  end

  def advanced_search(conn, params) do
    case UserQuery.advanced_search(params) do
      {:ok, users} -> json(conn, %{users: users})
      {:error, _} -> 
        conn
        |> put_status(:internal_server_error)
        |> json(%{error: "Search failed"})
    end
  end
end

defmodule AdminDashboardWeb.Router do
  use AdminDashboardWeb, :router

  pipeline :api do
    plug :accepts, ["json"]
  end

  scope "/api/admin", AdminDashboardWeb do
    pipe_through :api

    get "/users", UserController, :index
    get "/users/search", UserController, :search
    get "/users/filter", UserController, :filter
    get "/users/date-range", UserController, :date_range
    get "/users/custom-filter", UserController, :custom_filter
    get "/users/advanced-search", UserController, :advanced_search
    get "/users/:id", UserController, :show
    delete "/users/:id", UserController, :delete
    put "/users/:id/role", UserController, :update_role
  end
end